queries.sparql:
PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?responsibility WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:responsibilityId ?cg . ?child a :Responsibilities ; p:id ?cg . ?l p:internshipId ?pg . ?parent a :Internships ; p:id ?pg . } GROUP BY ?child }
  ?child p:responsibility ?responsibility .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Internships } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  collective: { SELECT ?responsibility WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:responsibilityId ?cg . ?child a :Responsibilities ; p:id ?cg . ?l p:internshipId ?pg . ?parent a :Internships ; p:id ?pg . } GROUP BY ?child }
  ?child p:responsibility ?responsibility .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Internships } }
  FILTER(?nf = ?total)
} }
  distributive: { SELECT ?title ?responsibility WHERE {
  ?internships_responsibilities a :Internships_Responsibilities .
  ?responsibilities a :Responsibilities .
  ?internships_responsibilities p:hasResponsibilities ?responsibilities .
  ?internships a :Internships .
  ?internships_responsibilities p:hasInternships ?internships .
  ?internships p:title ?title .
  ?responsibilities p:responsibility ?responsibility .
} }
}
